HMAC_SECRET = os.getenv("HMAC_SECRET", "dev-secret-change-me")


def _now() -> int:
    return int(time.time())


def _norm_addr(addr: str) -> str:
    if not isinstance(addr, str):
        raise ValueError("Address must be a string")
    addr = addr.strip()
    if not Web3.is_address(addr):
        raise ValueError("Invalid address")
    return Web3.to_checksum_address(addr)


def _hmac_sha256(data: bytes) -> str:
    return hmac.new(HMAC_SECRET.encode("utf-8"), data, hashlib.sha256).hexdigest()


def _sign_token(payload: Dict[str, Any]) -> str:
    body = json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")
    sig = _hmac_sha256(body)
    return sig + "." + body.decode("utf-8")


def _verify_token(token: str) -> Dict[str, Any]:
    if not token or "." not in token:
        raise ValueError("Invalid token format")
    sig, body = token.split(".", 1)
    body_bytes = body.encode("utf-8")
    expected = _hmac_sha256(body_bytes)
    if not hmac.compare_digest(sig, expected):
        raise ValueError("Invalid token signature")
    payload = json.loads(body)
    exp = int(payload.get("exp", 0))
    if exp <= _now():
        raise ValueError("Token expired")
    return payload


def build_signin_message(address: str, nonce: str, issued_at: int, chain_id: int = CHAIN_ID) -> str:
    addr = _norm_addr(address)
    # Minimal SIWE-like message (personal_sign / eth_sign compatible)
    return (
        f"{DOMAIN} wants you to sign in with your Ethereum account:\n"
        f"{addr}\n\n"
        f"Sign in to {APP_NAME}\n\n"
        f"URI: https://{DOMAIN}\n"
        f"Version: 1\n"
        f"Chain ID: {chain_id}\n"
        f"Nonce: {nonce}\n"
        f"Issued At: {time.strftime('%Y-%m-%dT%H:%M:%SZ', time.gmtime(issued_at))}"
    )


class NonceRecord:
    __slots__ = ("nonce", "address", "issued_at", "expires_at", "used")

    def __init__(self, nonce: str, address: str, issued_at: int, expires_at: int):
        self.nonce = nonce
        self.address = address
        self.issued_at = issued_at
        self.expires_at = expires_at
        self.used = False


class NonceStore:
    def __init__(self):
        self._by_nonce: Dict[str, NonceRecord] = {}

    def create(self, address: str) -> NonceRecord:
        addr = _norm_addr(address)
        nonce = secrets.token_urlsafe(16)
        issued_at = _now()
        rec = NonceRecord(nonce=nonce, address=addr, issued_at=issued_at, expires_at=issued_at + NONCE_TTL_SECONDS)
        self._by_nonce[nonce] = rec
        return rec

    def get(self, nonce: str) -> Optional[NonceRecord]:
        rec = self._by_nonce.get(nonce)
        if not rec:
            return None
        if rec.expires_at <= _now():
            self._by_nonce.pop(nonce, None)
            return None
        return rec

    def mark_used(self, nonce: str) -> None:
        rec = self._by_nonce.get(nonce)
        if rec:
            rec.used = True

    def cleanup(self) -> None:
        t = _now()
        expired = [n for n, r in self._by_nonce.items() if r.expires_at <= t or r.used]
        for n in expired:
            self._by_nonce.pop(n, None)


