def recover_address_from_message(message: str, signature: str) -> str:
    if not isinstance(signature, str) or not signature.startswith("0x"):
        raise ValueError("Signature must be a 0x-prefixed hex string")
    recovered = Web3().eth.account.recover_message(
        Web3.solidity_keccak(["string"], [message]).hex(),  # type: ignore
        signature=signature,
    )


@app.post("/auth/nonce", response_model=NonceResponse)
async def create_nonce(payload: NonceRequest):
    if payload.chain_id != CHAIN_ID:
        raise HTTPException(status_code=400, detail="Unsupported chain_id")
    rec = nonce_store.create(payload.address)
    msg = build_signin_message(rec.address, rec.nonce, rec.issued_at, chain_id=payload.chain_id)
    return NonceResponse(
        address=rec.address,
        nonce=rec.nonce,
        issued_at=rec.issued_at,
        expires_at=rec.expires_at,
        message=msg,
        chain_id=payload.chain_id,
    )


def _recover_personal_sign_address(message: str, signature: str) -> str:
    from eth_account.messages import encode_defunct

    msg = encode_defunct(text=message)
    addr = Web3().eth.account.recover_message(msg, signature=signature)
    return _norm_addr(addr)


@app.post("/auth/verify", response_model=VerifyResponse)
async def verify_signature(payload: VerifyRequest):
    if payload.chain_id != CHAIN_ID:
        raise HTTPException(status_code=400, detail="Unsupported chain_id")

    try:
        addr = _norm_addr(payload.address)
    except ValueError as e:
        raise HTTPException(status_code=400, detail=str(e))

    rec = nonce_store.get(payload.nonce)
    if not rec:
        raise HTTPException(status_code=400, detail="Invalid or expired nonce")
    if rec.used:
        raise HTTPException(status_code=400, detail="Nonce already used")
    if rec.address != addr:
        raise HTTPException(status_code=400, detail="Nonce not issued for this address")

    message = build_signin_message(addr, rec.nonce, rec.issued_at, chain_id=payload.chain_id)

    try:
        recovered = _recover_personal_sign_address(message, payload.signature)
    except Exception:
        raise HTTPException(status_code=401, detail="Signature verification failed")

    if recovered != addr:
        raise HTTPException(status_code=401, detail="Recovered address does not match")

    nonce_store.mark_used(payload.nonce)
    nonce_store.cleanup()

    iat = _now()
    exp = iat + TOKEN_TTL_SECONDS
    token_payload = {
        "sub": addr,
        "iat": iat,
        "exp": exp,
        "iss": ISSUER,
        "chain_id": payload.chain_id,
    }
    token = _sign_token(token_payload)
    return VerifyResponse(ok=True, address=addr, token=token, expires_at=exp)


def get_current_user(request: Request) -> Dict[str, Any]:
    auth = request.headers.get("Authorization", "")
    if not auth.startswith("Bearer "):
        raise HTTPException(status_code=401, detail="Missing bearer token")
    token = auth[len("Bearer ") :].strip()
    try:
        payload = _verify_token(token)
    except Exception:
        raise HTTPException(status_code=401, detail="Invalid token")
    return payload


